-- Add columns to question templates to support the full working paper structure
ALTER TABLE public.aml_program_question_templates
  ADD COLUMN IF NOT EXISTS regulatory_category text,
  ADD COLUMN IF NOT EXISTS test_procedure text,
  ADD COLUMN IF NOT EXISTS analyst_guidance text,
  ADD COLUMN IF NOT EXISTS pass_criteria text,
  ADD COLUMN IF NOT EXISTS max_points integer DEFAULT 2,
  ADD COLUMN IF NOT EXISTS section_code text,
  ADD COLUMN IF NOT EXISTS section_name text,
  ADD COLUMN IF NOT EXISTS question_code text,
  ADD COLUMN IF NOT EXISTS is_new_or_updated boolean DEFAULT false;

-- Add columns to control results to support working paper output
ALTER TABLE public.aml_pp_control_results
  ADD COLUMN IF NOT EXISTS risk_rating text,
  ADD COLUMN IF NOT EXISTS points_achieved integer DEFAULT 0,
  ADD COLUMN IF NOT EXISTS observation_best_practice text,
  ADD COLUMN IF NOT EXISTS evidence_reviewed text;

-- Clear existing core_controls templates (we are replacing with full working paper)
DELETE FROM public.aml_program_question_templates
WHERE submodule = 'policies_procedures' AND control_area = 'core_controls';

